const rawData = $input.item.json;
const data = rawData.body || rawData;

const name = data.name || 'N/A';
const email = data.email || 'N/A';
const message = data.message || '';
const ts = new Date().toLocaleString('sv-SE', { timeZone: 'Europe/Stockholm' });

const text = `\u{1F3AF} <b>New Early Access \u2013 The Print Route</b>\n\n<b>Name:</b> ${name}\n<b>Email:</b> ${email}` + (message ? `\n<b>Message:</b> ${message}` : '') + `\n<b>Time:</b> ${ts}`;

const token = $env.TELEGRAM_BOT_TOKEN || '8683132686:AAF5yJ206OcLKsSBx0n4Nm4uBAxcQlRbwyc';
const chatId = '-1003767033253';

try {
  const response = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' })
  });
  return [{ json: { success: response.ok } }];
} catch (e) {
  return [{ json: { success: false } }];
}
